import React, { useEffect, useState } from 'react';
import { useParams } from 'react-router-dom';
import { useAuth } from '../contexts/AuthContext';
import api from '../utils/api';
import Box from '@mui/material/Box';
import Typography from '@mui/material/Typography';
import Avatar from '@mui/material/Avatar';
import Button from '@mui/material/Button';
import Tabs from '@mui/material/Tabs';
import Tab from '@mui/material/Tab';
import Grid from '@mui/material/Grid';
import Skeleton from '@mui/material/Skeleton';
import MediaCard from '../components/MediaCard';

const Channel = () => {
  const { id } = useParams();
  const { user } = useAuth();
  const [channel, setChannel] = useState(null);
  const [media, setMedia] = useState([]);
  const [loading, setLoading] = useState(true);
  const [tab, setTab] = useState(0);
  const [isSubscribed, setIsSubscribed] = useState(false);

  useEffect(() => {
    (async () => {
      try {
        const [channelRes, mediaRes] = await Promise.all([
          api.get(`/users/${id}`),
          api.get('/media/feed', { params: { limit: 50 } }),
        ]);
        setChannel(channelRes.data);
        setMedia((mediaRes.data.items || []).filter((m) => m.uploader?._id === id));
        if (user) {
          setIsSubscribed(channelRes.data.subscribers?.includes(user._id));
        }
      } catch (err) {
        console.error(err);
      } finally {
        setLoading(false);
      }
    })();
  }, [id, user]);

  const handleSubscribe = async () => {
    if (!user) return;
    try {
      await api.post(`/users/${id}/subscribe`);
      setIsSubscribed(!isSubscribed);
      setChannel((prev) => ({
        ...prev,
        subscribers: isSubscribed
          ? prev.subscribers.filter((s) => s !== user._id)
          : [...prev.subscribers, user._id],
      }));
    } catch (err) {
      console.error('Subscribe failed:', err);
    }
  };

  if (loading) {
    return (
      <Box>
        <Skeleton variant="rounded" height={200} sx={{ borderRadius: '12px', mb: 3 }} />
        <Box sx={{ display: 'flex', gap: 2, mb: 3 }}>
          <Skeleton variant="circular" width={80} height={80} />
          <Box sx={{ flex: 1 }}>
            <Skeleton width="30%" height={32} />
            <Skeleton width="15%" />
          </Box>
        </Box>
      </Box>
    );
  }

  if (!channel) {
    return <Typography sx={{ textAlign: 'center', mt: 8 }}>Channel not found</Typography>;
  }

  return (
    <Box>
      {/* Banner */}
      <Box
        sx={{
          height: 200,
          borderRadius: '12px',
          background: 'linear-gradient(135deg, #1a1a2e, #16213e, #0f3460)',
          mb: 3,
        }}
      />

      {/* Channel header */}
      <Box sx={{ display: 'flex', alignItems: 'center', gap: 2, mb: 3 }}>
        <Avatar
          src={channel.profilePic}
          sx={{ width: 80, height: 80, bgcolor: '#c4302b', fontSize: 32 }}
        >
          {channel.username?.[0]?.toUpperCase()}
        </Avatar>
        <Box sx={{ flex: 1 }}>
          <Typography variant="h5" sx={{ fontWeight: 600 }}>{channel.username}</Typography>
          <Typography variant="body2" color="text.secondary">
            @{channel.username?.toLowerCase()} &middot; {channel.subscribers?.length || 0} subscribers &middot; {media.length} videos
          </Typography>
          {channel.bio && (
            <Typography variant="body2" color="text.secondary" sx={{ mt: 0.5 }}>{channel.bio}</Typography>
          )}
        </Box>
        {user && user._id !== id && (
          <Button
            variant="contained"
            onClick={handleSubscribe}
            sx={{
              borderRadius: 20,
              bgcolor: isSubscribed ? '#272727' : '#fff',
              color: isSubscribed ? '#fff' : '#000',
              fontWeight: 600,
              '&:hover': { bgcolor: isSubscribed ? '#333' : '#e0e0e0' },
            }}
          >
            {isSubscribed ? 'Subscribed' : 'Subscribe'}
          </Button>
        )}
      </Box>

      {/* Tabs */}
      <Tabs
        value={tab}
        onChange={(_, v) => setTab(v)}
        sx={{
          borderBottom: '1px solid #303030',
          mb: 3,
          '& .MuiTab-root': { color: '#aaa', textTransform: 'none', fontWeight: 500 },
          '& .Mui-selected': { color: '#fff' },
        }}
      >
        <Tab label="Videos" />
        <Tab label="About" />
      </Tabs>

      {tab === 0 && (
        <Grid container spacing={2}>
          {media.length > 0 ? (
            media.map((m) => (
              <Grid item xs={12} sm={6} md={4} lg={3} key={m._id}>
                <MediaCard media={m} />
              </Grid>
            ))
          ) : (
            <Grid item xs={12}>
              <Box sx={{ textAlign: 'center', py: 8 }}>
                <Typography variant="h6" color="text.secondary">No uploads yet</Typography>
              </Box>
            </Grid>
          )}
        </Grid>
      )}

      {tab === 1 && (
        <Box sx={{ maxWidth: 600 }}>
          <Typography variant="subtitle2" sx={{ mb: 1, fontWeight: 600 }}>Description</Typography>
          <Typography variant="body2" color="text.secondary">{channel.bio || 'No description'}</Typography>
          <Typography variant="subtitle2" sx={{ mt: 3, mb: 1, fontWeight: 600 }}>Stats</Typography>
          <Typography variant="body2" color="text.secondary">
            Joined {new Date(channel.createdAt).toLocaleDateString('en-US', { year: 'numeric', month: 'long' })}
          </Typography>
        </Box>
      )}
    </Box>
  );
};

export default Channel;
